import { Component, Input } from '@angular/core';
import { NgClass, NgStyle } from '@angular/common';

/**
 * Tipo equivalente a `CSSProperties['flexDirection']`.
 * Soporta todos los valores estándar de `flex-direction`.
 */
export type FlexDirection =
  | 'row'
  | 'row-reverse'
  | 'column'
  | 'column-reverse'
  | 'inherit'
  | 'initial'
  | 'revert'
  | 'revert-layer'
  | 'unset';

/**
 * `Flex`
 * ------
 * Contenedor `display: flex` parametrizable.
 * Las "custom props" no se filtran al DOM porque en Angular los `@Input`
 * no se reenvían como atributos HTML.
 */
@Component({
  selector: 'Flex',
  standalone: true,
  imports: [NgClass, NgStyle],
  templateUrl: './flex.html',
  styleUrls: ['./flex.css'],
})
export class FlexComponent {
  /** Dirección del eje principal. */
  @Input() direction: FlexDirection = 'row';
  /** `justify-content` (CSS). */
  @Input() justifyContent?: string;
  /** `align-items` (CSS). */
  @Input() alignItems?: string;
  /** `gap` (CSS). */
  @Input() gap?: string;
  /** `flex` shorthand (CSS). */
  @Input() flex?: string;
  /** `overflow` (CSS). */
  @Input() overflow?: string;
  /** Si `true`, `flex-wrap: nowrap` (por defecto `wrap`). */
  @Input() noWrap = false;
  /** Si `true`, añade `min-width: 0` (row) o `min-height: 0` (column). */
  @Input() shrinkable = false;
  /** Clases extra para el contenedor. */
  @Input() className = '';

  get classes(): string {
    return `flex ${this.className}`.trim();
  }

  get styles(): Record<string, string> {
    return {
      display: 'flex',
      'flex-direction': this.direction,
      'flex-wrap': this.noWrap ? 'nowrap' : 'wrap',
      overflow: this.overflow ?? '',
      flex: this.flex ?? '',
      gap: this.gap ?? '',
      'justify-content': this.justifyContent ?? '',
      'align-items': this.alignItems ?? '',
      ...(this.shrinkable
        ? this.direction === 'row'
          ? { 'min-width': '0' }
          : { 'min-height': '0' }
        : {}),
    };
  }
}

import {
  ChangeDetectionStrategy,
  ChangeDetectorRef,
  Component,
  EventEmitter,
  inject,
  Input,
  OnChanges,
  OnDestroy,
  OnInit,
  Output,
  SimpleChanges,
  Type,
  ViewChild,
  TemplateRef,
} from '@angular/core';
import { NgComponentOutlet, NgTemplateOutlet } from '@angular/common';

import { IconProps } from '@ui/icon/icon.interface';
import { TypographyType } from '@styles/types/typography';
import designConstants from '@styles/constants';
import {
  TooltipComponent,
  TooltipSide,
  TooltipVariantType,
} from '@ui/tooltip/tooltip';
import { LoadingTimeoutWrapperComponent } from '@ui/loading-timeout-wrapper/loading-timeout-wrapper';
import { getFocusStyling } from '@utils/styling';

import {
  ButtonLinkProps,
  ButtonStyleType,
  ButtonTooltip,
  ButtonVariant,
  IconButtonProps,
} from '@ui/button/types';
import { getVariantClasses } from '@ui/button/variants';

/**
 * `IconButton`
 * ------------
 * Botón cuadrado (aspect-ratio 1:1) que contiene un único ícono.
 * Réplica Angular del `IconButton` del proyecto React.
 *
 * Mismas capacidades que `Button` (variants, styleTypes, loading
 * wrapper, tooltip, `asLink`) salvo que no tiene label.
 */
@Component({
  selector: 'IconButton',
  standalone: true,
  imports: [
    NgTemplateOutlet,
    NgComponentOutlet,
    TooltipComponent,
    LoadingTimeoutWrapperComponent,
  ],
  changeDetection: ChangeDetectionStrategy.OnPush,
  templateUrl: './icon-button.html',
})
export class IconButtonComponent
  implements OnInit, OnChanges, OnDestroy, IconButtonProps
{
  // -------------------------------------------------------------------------
  // Inputs
  // -------------------------------------------------------------------------

  @Input() variant: ButtonVariant = 'primary';
  @Input() styleType: ButtonStyleType = 'default';
  @Input() transparent = false;
  @Input() compact = false;
  @Input() disabled = false;
  @Input() isLoading = false;
  @Input() isSubmit = false;
  @Input() fontSize: TypographyType = 'bodyS';

  /** Componente Angular que se renderiza dentro del botón. */
  @Input({ required: true }) Icon!: Type<unknown>;
  @Input() iconProps: IconProps = {};

  /** Ancho explícito del botón. Si se omite, usa aspect-ratio 1:1. */
  @Input() width?: string;

  @Input() tooltip?: ButtonTooltip;
  @Input() tooltipSide: TooltipSide = 'bottom';
  @Input() tooltipVariant: TooltipVariantType = 'dark';
  @Input() labelText?: string;
  @Input() timeout?: number;
  @Input() disableOnTimeout = true;
  @Input() asLink = false;
  @Input() linkProps?: ButtonLinkProps;
  @Input() className = '';

  // -------------------------------------------------------------------------
  // Outputs
  // -------------------------------------------------------------------------

  @Output() click = new EventEmitter<MouseEvent>();

  // -------------------------------------------------------------------------
  // Estado interno
  // -------------------------------------------------------------------------

  @ViewChild('buttonTpl', { static: true }) buttonTpl!: TemplateRef<unknown>;

  private cdr = inject(ChangeDetectorRef);
  private timeoutId?: ReturnType<typeof setTimeout>;
  runningTimeout = false;

  // -------------------------------------------------------------------------
  // Lifecycle
  // -------------------------------------------------------------------------

  ngOnInit(): void {
    if (this.timeout) this.startTimeout();
  }
  ngOnChanges(changes: SimpleChanges): void {
    if (changes['timeout']) {
      if (this.timeout) this.startTimeout();
      else this.clearTimeout();
    }
  }
  ngOnDestroy(): void {
    this.clearTimeout();
  }

  // -------------------------------------------------------------------------
  // API pública
  // -------------------------------------------------------------------------

  resetTimeout = (): void => {
    this.clearTimeout();
    if (this.timeout) {
      this.runningTimeout = true;
      this.cdr.markForCheck();
      this.timeoutId = setTimeout(() => {
        this.runningTimeout = false;
        this.cdr.markForCheck();
      }, this.timeout);
    }
  };

  onClick(event: MouseEvent): void {
    if (this.isEffectivelyDisabled) {
      event.preventDefault();
      event.stopPropagation();
      return;
    }
    this.click.emit(event);
  }

  // -------------------------------------------------------------------------
  // Getters
  // -------------------------------------------------------------------------

  get isEffectivelyDisabled(): boolean {
    return (
      this.disabled ||
      this.isLoading ||
      (this.runningTimeout && this.disableOnTimeout)
    );
  }

  get showWrapper(): boolean {
    return this.isLoading || this.runningTimeout;
  }

  get hasActiveTimeout(): boolean {
    return !!this.timeout && this.runningTimeout;
  }

  get buttonClasses(): string {
    const aspect = this.width ? '' : 'aspect-square';
    const layout = [
      'inline-flex items-center justify-center',
      'rounded-lg',
      'cursor-pointer select-none',
      'border border-solid',
      this.compact ? 'p-1' : 'p-2',
      this.width ? `w-[${this.width}]` : '',
      aspect,
    ];

    if (this.showWrapper) {
      return [
        ...layout,
        'bg-transparent border-transparent',
        'disabled:opacity-0',
        this.getFocusClasses(),
      ].join(' ');
    }
    return [
      ...layout,
      getVariantClasses(this.variant, this.styleType, this.transparent),
      this.getFocusClasses(),
    ].join(' ');
  }

  get iconInputs(): Record<string, unknown> {
    const props: Record<string, unknown> = { ...this.iconProps };
    if (props['size'] === undefined) {
      props['size'] = designConstants.typography.fontSize[this.fontSize];
    }
    return props;
  }

  get computedRel(): string | null {
    if (!this.asLink) return null;
    const explicit = this.linkProps?.rel;
    if (explicit) return explicit;
    if (this.linkProps?.target === '_blank') return 'noopener noreferrer';
    return null;
  }

  // -------------------------------------------------------------------------
  // Privados
  // -------------------------------------------------------------------------

  private startTimeout(): void {
    this.clearTimeout();
    this.runningTimeout = true;
    this.cdr.markForCheck();
    this.timeoutId = setTimeout(() => {
      this.runningTimeout = false;
      this.cdr.markForCheck();
    }, this.timeout);
  }

  private clearTimeout(): void {
    if (this.timeoutId) {
      clearTimeout(this.timeoutId);
      this.timeoutId = undefined;
    }
  }

  private getFocusClasses(): string {
    return getFocusStyling('visible');
  }
}

import {
  Component,
  Input,
  ChangeDetectionStrategy,
} from '@angular/core';
import { CommonModule } from '@angular/common';

import { CircleInfoIconLightComponent } from '@ui/icon/circle-info-icon-light';
import { TooltipComponent } from '@ui/tooltip/tooltip';

/**
 * `InfoIconWithTooltip`
 * --------------------
 * Muestra un `IconCircleInfoLight` con un tooltip al hacer hover.
 *
 * Comportamiento:
 *  - El `tooltip` puede ser un texto plano.
 *  - Se controla con `color` (cualquier valor CSS o `currentColor`).
 *  - Detiene la propagación del click para no interferir con el padre.
 *
 * Usa el componente `Tooltip` del design system.
 */
@Component({
  selector: 'InfoIconWithTooltip',
  standalone: true,
  imports: [CommonModule, CircleInfoIconLightComponent, TooltipComponent],
  changeDetection: ChangeDetectionStrategy.OnPush,
  template: `
    <Tooltip
      [content]="tooltip"
      [variant]="variant"
      [side]="side"
      [sideOffset]="sideOffset"
      [align]="align"
      [delayDuration]="delayDuration"
      [className]="tooltipClassName"
    >
      <button
        type="button"
        class="inline-flex items-center justify-center bg-transparent border-0 p-0 cursor-pointer"
        [ngClass]="triggerClassName"
        (click)="stopPropagation($event)"
        [attr.aria-label]="tooltip || null"
      >
        <IconCircleInfoLight
          [size]="size"
          [color]="color"
          [dataTestId]="dataTestId"
        />
      </button>
    </Tooltip>
  `,
})
export class InfoIconWithTooltipComponent {
  /** Texto del tooltip. */
  @Input() tooltip = '';
  /** Color del icono (CSS color). Por defecto `currentColor`. */
  @Input() color = 'currentColor';
  /** Tamaño del icono. */
  @Input() size: number | string = 12;
  /** `data-testid` que se delega al icono. */
  @Input() dataTestId?: string;
  /** Clases extra para el contenedor exterior. */
  @Input() className = '';
  /** Clases para el botón disparador. */
  @Input() triggerClassName =
    'text-gray-500 hover:text-gray-700 dark:text-gray-400 dark:hover:text-gray-200';
  /** Variante del tooltip. */
  @Input() variant: 'light' | 'dark' = 'light';
  /** Lado del tooltip. */
  @Input() side: 'top' | 'right' | 'bottom' | 'left' = 'bottom';
  /** Distancia (px) entre el tooltip y el icono. */
  @Input() sideOffset = 8;
  /** Alineación del tooltip. */
  @Input() align: 'start' | 'center' | 'end' = 'start';
  /** Retraso (ms) para mostrar el tooltip. */
  @Input() delayDuration = 200;

  get tooltipClassName(): string {
    return this.className;
  }

  stopPropagation(event: MouseEvent): void {
    event.stopPropagation();
  }
}

import {
  Component,
  Input,
  ElementRef,
  ViewChild,
  AfterViewInit,
  OnChanges,
  OnDestroy,
  SimpleChanges,
  ChangeDetectionStrategy,
  ChangeDetectorRef,
  inject,
} from '@angular/core';
import { CommonModule } from '@angular/common';

import designConstants, { TypographyType, FontWeightType, ColorType } from '@styles/constants';
import { TooltipComponent } from '@ui/tooltip/tooltip';
import { TooltipSide } from '@ui/tooltip/tooltip.types';

/** Elementos HTML válidos para el slot principal. */
export type LabelAs = 'small' | 'span' | 'p' | 'strong';

/** `typographyType` → elemento HTML por defecto. */
const TYPE_TO_HTML_ELEMENT: Record<TypographyType, string> = {
  bodyXxs: 'small',
  bodyXs: 'span',
  bodyS: 'p',
  HeadingXs: 'h6',
  HeadingS: 'h5',
  HeadingM: 'h4',
  HeadingL: 'h3',
  HeadingXl: 'h2',
  HeadingXxl: 'h1',
  HeadingTV: 'h1',
};

/**
 * `Label`
 * -------
 * Aplica tipografía (tamaño, line-height, peso) desde `designConstants`
 * y, opcionalmente, detecta overflow para envolver el texto en un
 * `Tooltip` con el contenido completo.
 *
 * Estructura: si `showTooltip` es `true`, el `<span>` se monta dentro de un
 * `<Tooltip variant="light" align="start" [content]="...">`. En caso contrario
 * se renderiza directamente.
 */
@Component({
  selector: 'Label',
  standalone: true,
  imports: [CommonModule, TooltipComponent],
  changeDetection: ChangeDetectionStrategy.OnPush,
  template: `
    @if (showTooltip) {
      <Tooltip
        variant="light"
        align="start"
        [content]="resolvedText"
        [side]="tooltipSide"
      >
        <span
          #container
          class="label wrap-break-word"
          [ngClass]="className"
          [ngStyle]="containerStyles"
          [attr.for]="for || null"
          [style.color]="resolvedColor"
          [style.font-weight]="resolvedWeight"
          [style.font-style]="italic ? 'italic' : null"
          [style.text-align]="align || null"
          [style.white-space]="!wrapText ? 'nowrap' : null"
          [style.overflow]="!wrapText || wrapMaxLines ? 'hidden' : null"
          [style.text-overflow]="!wrapText || wrapMaxLines ? 'ellipsis' : null"
          [style.display]="wrapText && wrapMaxLines ? '-webkit-box' : null"
          [style.-webkit-box-orient]="wrapText && wrapMaxLines ? 'vertical' : null"
          [style.-webkit-line-clamp]="wrapText && wrapMaxLines ? wrapMaxLines.toString() : null"
        >
          <span #textEl class="label__text">
            @if (text) {
              {{ text }}
            } @else {
              <ng-content></ng-content>
            }
          </span>
        </span>
      </Tooltip>
    } @else {
      <span
        #container
        class="label wrap-break-word"
        [ngClass]="className"
        [ngStyle]="containerStyles"
        [attr.for]="for || null"
        [style.color]="resolvedColor"
        [style.font-weight]="resolvedWeight"
        [style.font-style]="italic ? 'italic' : null"
        [style.text-align]="align || null"
        [style.white-space]="!wrapText ? 'nowrap' : null"
        [style.overflow]="!wrapText || wrapMaxLines ? 'hidden' : null"
        [style.text-overflow]="!wrapText || wrapMaxLines ? 'ellipsis' : null"
        [style.display]="wrapText && wrapMaxLines ? '-webkit-box' : null"
        [style.-webkit-box-orient]="wrapText && wrapMaxLines ? 'vertical' : null"
        [style.-webkit-line-clamp]="wrapText && wrapMaxLines ? wrapMaxLines.toString() : null"
      >
        <span #textEl class="label__text">
          @if (text) {
            {{ text }}
          } @else {
            <ng-content></ng-content>
          }
        </span>
      </span>
    }
  `,
  styles: [
    `
      .label {
        display: inline-block;
        max-width: 100%;
      }
    `,
  ],
})
export class LabelComponent implements AfterViewInit, OnChanges, OnDestroy {
  /** Tag HTML concreto. Si se omite, se infiere por `type`. */
  @Input() as?: LabelAs;
  /** Asocia el label a un input por su `id` (atributo `for` del HTML). */
  @Input() for?: string;
  /** Texto a mostrar (alternativa al slot). */
  @Input() text?: string;
  /** Tipografía. */
  @Input() type: TypographyType = 'bodyXs';
  /** `font-weight` (si se omite, usa el de `fontWeightByTypographyType[type]`). */
  @Input() weight?: FontWeightType;
  /** Color semántico. */
  @Input() color?: ColorType;
  /** Si `false`, el texto no hace wrap (default). */
  @Input() wrapText = false;
  /** Máx. de líneas cuando `wrapText` es `true`. Activa line-clamp. */
  @Input() wrapMaxLines?: number;
  /** Offset (px) para restar al espacio disponible al detectar overflow. */
  @Input() availableSpaceOffset = 0;
  /** Aplica `font-style: italic`. */
  @Input() italic = false;
  /** Re-comprueba el overflow tras el primer render. */
  @Input() refreshOnLoad = false;
  /** `text-align` (CSS). */
  @Input() align?: 'left' | 'right' | 'center' | 'justify';
  /** Clases extra para el contenedor. */
  @Input() className = '';
  /** Lado del tooltip. */
  @Input() tooltipSide: TooltipSide = 'bottom';

  @ViewChild('container') containerRef?: ElementRef<HTMLElement>;
  @ViewChild('textEl') textRef?: ElementRef<HTMLElement>;

  isOverflowing = false;

  private cdr = inject(ChangeDetectorRef);
  private overflowTimeout?: ReturnType<typeof setTimeout>;

  // -------------------------------------------------------------------------
  // Getters
  // -------------------------------------------------------------------------

  get resolvedText(): string {
    return this.text ?? '';
  }

  get resolvedColor(): string {
    if (!this.color) return 'currentColor';
    return designConstants.colors[this.color] ?? 'currentColor';
  }

  get resolvedWeight(): string {
    const w =
      this.weight ?? designConstants.typography.fontWeightByTypographyType[this.type];
    return designConstants.typography.fontWeight[w].toString();
  }

  get resolvedHtmlElement(): string {
    return this.as ?? TYPE_TO_HTML_ELEMENT[this.type];
  }

  get containerStyles(): Record<string, string> {
    return {
      'font-size': designConstants.typography.fontSize[this.type],
      'line-height': designConstants.typography.lineHeight[this.type],
    };
  }

  get showTooltip(): boolean {
    return this.isOverflowing && (!this.wrapText || !!this.wrapMaxLines);
  }

  // -------------------------------------------------------------------------
  // Lifecycle
  // -------------------------------------------------------------------------

  ngAfterViewInit(): void {
    this.scheduleOverflowCheck();
  }

  ngOnChanges(changes: SimpleChanges): void {
    if (
      changes['text'] ||
      changes['type'] ||
      changes['wrapText'] ||
      changes['wrapMaxLines'] ||
      changes['availableSpaceOffset']
    ) {
      this.scheduleOverflowCheck();
    }
  }

  ngOnDestroy(): void {
    if (this.overflowTimeout) clearTimeout(this.overflowTimeout);
  }

  // -------------------------------------------------------------------------
  // Overflow detection
  // -------------------------------------------------------------------------

  private scheduleOverflowCheck(): void {
    if (this.overflowTimeout) clearTimeout(this.overflowTimeout);
    this.overflowTimeout = setTimeout(() => this.checkOverflow(), 0);
  }

  private checkOverflow(): void {
    const container = this.containerRef?.nativeElement;
    const text = this.textRef?.nativeElement;
    if (!container || !text) return;

    const axis: 'offsetHeight' | 'offsetWidth' = this.wrapText
      ? 'offsetHeight'
      : 'offsetWidth';
    const containerSize = container[axis] as number;
    const textSize = text[axis] as number;
    const available = containerSize - this.availableSpaceOffset;

    this.isOverflowing = textSize > available;
    this.cdr.markForCheck();
  }
}

import {
  ChangeDetectionStrategy,
  Component,
  Input,
} from '@angular/core';
import { NgClass, NgStyle } from '@angular/common';

import { ButtonStyleType, ButtonVariant } from '@ui/button/types';
import { getVariantClasses } from '@ui/button/variants';

/**
 * `LoadingTimeoutWrapper`
 * -----------------------
 * Contenedor presentacional que envuelve un `Button` (o `IconButton`)
 * cuando está en estado `isLoading` o `runningTimeout`.
 *
 * Responsabilidades:
 *  1. Aportar el marco visual (background, border, color) que el botón
 *     interior "cede" (queda borderless) para que la progress bar pueda
 *     ser recortada por el `border-radius` del wrapper.
 *  2. Pintar una progress bar animada de 0 → 100% sobre `timeout` ms.
 *  3. Respetar `fullWidth` para que el wrapper ocupe el contenedor padre.
 *
 * Réplica Angular del `LoadingTimeoutWrapper` del proyecto React.
 */
@Component({
  selector: 'LoadingTimeoutWrapper',
  standalone: true,
  imports: [NgClass, NgStyle],
  changeDetection: ChangeDetectionStrategy.OnPush,
  templateUrl: './loading-timeout-wrapper.html',
  styleUrls: ['./loading-timeout-wrapper.css'],
})
export class LoadingTimeoutWrapperComponent {
  /** Variante visual. */
  @Input() variant: ButtonVariant = 'primary';

  /** Estilo semántico. */
  @Input() styleType: ButtonStyleType = 'default';

  /** Si `true`, el wrapper ocupa el 100% del ancho del contenedor. */
  @Input() fullWidth = false;

  /** Si `true`, el fondo es transparente. */
  @Input() transparent = false;

  /** Duración de la progress bar (ms). Si es 0/undefined, no se anima. */
  @Input() timeout?: number;

  /** Clases extra para el contenedor. */
  @Input() className = '';

  get containerClasses(): string {
    return [
      getVariantClasses(this.variant, this.styleType, this.transparent),
      this.fullWidth ? 'w-full' : 'inline-flex',
      'relative overflow-hidden',
      'border border-solid',
      'rounded-lg',
      'cursor-pointer select-none',
      this.className,
    ]
      .filter(Boolean)
      .join(' ');
  }

  /**
   * Estilo en línea que pasa la duración al CSS de la progress bar
   * vía variable CSS (Tailwind no tiene una utility para esto).
   */
  get progressStyle(): Record<string, string> {
    return this.timeout
      ? { animationDuration: `${this.timeout}ms` }
      : { display: 'none' };
  }
}

styleUrlsData.data:
/*
 * Progress bar animada que recorre de izquierda a derecha mientras
 * corre el `timeout`. Usa `transform: scaleX` (compositor-friendly)
 * en lugar de `width` (re-paint en cada frame).
 *
 * El color se toma de `currentColor` (que viene del wrapper) con
 * 20% de opacidad para que combine con cualquier variant.
 */
.loading-timeout-wrapper__progress {
  position: absolute;
  inset: 0;
  background-color: currentColor;
  opacity: 0.2;
  transform-origin: left center;
  animation-name: ltw-progress-fill;
  animation-timing-function: linear;
  animation-fill-mode: forwards;
  pointer-events: none;
  border-radius: inherit;
}

@keyframes ltw-progress-fill {
  from {
    transform: scaleX(0);
  }
  to {
    transform: scaleX(1);
  }
}

